import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"龙卷闪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/龙卷闪.md","filePath":"4.资源分区/6.技艺及称号/武技类/龙卷闪.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/龙卷闪.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"龙卷闪",tabindex:"-1"},[s("龙卷闪 "),e("a",{class:"header-anchor",href:"#龙卷闪","aria-label":'Permalink to "龙卷闪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="龙卷闪-1" tabindex="-1">龙卷闪 <a class="header-anchor" href="#龙卷闪-1" aria-label="Permalink to &quot;龙卷闪&quot;">​</a></h1><p>龙卷闪<br> C+1000<br> 在古老的武学体系中，龙卷闪源于对自然元素之力的精妙掌控。传说中，强大的武术大师观察到龙卷风那毁天灭地的力量，经过无数次的研习与试验，将龙卷风的劲力与防御性相结合，创造出了这一独特而强大的技巧。如同龙卷风既能席卷一切又能保护风眼中心的宁静。</p><p>你以一个标准动作，消耗3点内力将周围的风气凝聚，形成微弱的风盾环绕身周，获得4点护盾，每点护盾都能抵消1点伤害，这些护盾在抵消4点伤害后便消散或者持续到你攻击三次之后便彻底消散。<br> 龙卷风不但有宁静的风眼，还有搅碎一切的风暴，你手中的白刃武器，如果没有手持，则选择身上一处能作为天武的部位上汇聚起龙卷风的力量，你在接下来三次攻击中获得8点近战攻击速度加值。<br> 以上效果如果没有被触发则持续一个场景。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
